<script setup lang="ts">import{ref}from'vue';import{useRouter,useRoute}from'vue-router';import{GraduationCap,Eye,EyeOff,LoaderCircle}from'lucide-vue-next';import{useAuthStore}from'@/stores/auth';const store=useAuthStore(),router=useRouter(),route=useRoute();const mode=ref<'login'|'register'>((route.query.mode as 'register')||'login'),name=ref(''),email=ref(''),password=ref(''),show=ref(false),busy=ref(false),error=ref(''),notice=ref('');async function submit(){error.value='';notice.value='';busy.value=true;try{if(mode.value==='login'){await store.signIn(email.value,password.value);await router.replace('/app')}else{const active=await store.signUp(email.value,password.value,name.value);if(active)await router.replace('/app');else notice.value='Проверьте почту и подтвердите регистрацию, затем войдите.'}}catch(e){error.value=e instanceof Error?e.message:'Не удалось выполнить запрос'}finally{busy.value=false}}</script><template><main class="auth-page"><section class="auth-art"><div class="brand light"><span class="brand-mark"><GraduationCap/></span><strong>Курсор</strong></div><div><span>ПЛАТФОРМА ДЛЯ АВТОРОВ</span><h1>Создавайте обучение, которое хочется проходить.</h1><p>Курсы, интерактивные уроки и аналитика в одном независимом пространстве.</p></div></section><section class="auth-form"><form @submit.prevent="submit"><div class="mobile-brand"><GraduationCap/>Курсор</div><p class="eyebrow">Добро пожаловать</p><h1>{{mode==='login'?'Войдите в аккаунт':'Создайте аккаунт'}}</h1><p>{{mode==='login'?'Продолжите работу над своими курсами.':'Личное пространство создастся автоматически.'}}</p><label v-if="mode==='register'">Ваше имя<input v-model="name" required autocomplete="name" placeholder="Алексей Петров"/></label><label>Email<input v-model="email" required type="email" autocomplete="email" placeholder="you@example.com"/></label><label>Пароль<div class="password"><input v-model="password" required :type="show?'text':'password'" minlength="6" autocomplete="current-password" placeholder="Минимум 6 символов"/><button type="button" @click="show=!show"><component :is="show?EyeOff:Eye"/></button></div></label><div v-if="error" class="auth-message error">{{error}}</div><div v-if="notice" class="auth-message notice">{{notice}}</div><button class="primary auth-submit" :disabled="busy"><LoaderCircle v-if="busy" class="spin"/>{{mode==='login'?'Войти':'Зарегистрироваться'}}</button><p class="auth-switch">{{mode==='login'?'Нет аккаунта?':'Уже есть аккаунт?'}} <button type="button" @click="mode=mode==='login'?'register':'login';error=''">{{mode==='login'?'Создать':'Войти'}}</button></p></form></section></main></template>